21	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
22	
23	function isComponent(type: string): boolean {
24	  return COMPONENT_TYPES.has(type);
25	}
26	
27	function isValidItemType(type: string): boolean {
28	  return type in MAIN_ITEMS || COMPONENT_TYPES.has(type);
29	}
30	
31	function computeComponentPremium(items: any[]): number {
32	  const componentCounts: Record<string, number> = {};
33	
34	  for (const item of items) {
35	    if (isComponent(item.type)) {
36	      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
